var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 보안국 청사 지하 조사실\\n<color=#ffd34c>레버넌트</color>, 반역죄 조사 중\\n조사 시작 후 ██시간째.","JPN":"グロニア保安局庁舎、地下調査室\\n<color=#ffd34c>レヴナント</color>、反逆罪調査中\\n調査開始から██時間経過","ENG":"Gronia Department of National Security’s Underground Interrogation Room\\n<color=#ffd34c>Revenant</color>, ██ hours after the start of the investigation.","TWN":"格羅尼亞安全局地下調查室\\n<color=#ffd34c>亡靈</color>，叛國罪調查中\\n調查開始後經過██小時","THA":"ห้องสอบปากคำใต้ดิน สำนักงานความมั่นคงแห่งชาติโกรเนีย\\n<color=#ffd34c>เรเวแนนต์</color> ██ ชั่วโมงหลังเริ่มการสอบปากคำ","VTN":"<color=#ffd34c>Revenant</color>\\nPhòng thẩm vấn Thế giới ngầm Cục An Ninh Quốc Gia Gronia, ██ giờ sau khi bắt đầu cuộc điều tra.","SCN":"格洛尼亚安全局总部地下调查室\\n<color=#ffd34c>亡灵</color>，叛国罪调查中\\n调查开始██小时后。","DEU":"Der unterirdische Befragungsraum der Gronia Department of National Security \\n <color=#ffd34c>Revenant</color> ██ Stunden nach Beginn der Untersuchung.","FRA":"Salle d'interrogatoire souterraine du Département de la sécurité nationale de Gronia\\n<color=#ffd34c>Revenant</color>, ██ heures après le début de l'enquête."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"ENG":"The following brown colored comments are written by Harrison"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"콜록……!","JPN":"ゲホッ……！","ENG":"*Cough!*","TWN":"咳咳……！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"사람이 말하는데 졸고 있으면 안 되지, 레버넌트.","JPN":"人が話してる最中にうとうとするとは感心しないな、レヴナント。","ENG":"It’s quite rude to doze off when someone is talking, Revenant.","TWN":"人家在說話，你怎麼可以睡著呢，亡靈。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……다 국장님 덕분이죠. 여기 온 뒤로 한숨도 못 잤으니까요.","JPN":"……すべて局長のおかげです。ここに来てから一睡もできませんでしたから。","ENG":"...That is all thanks to you. I haven’t been able to sleep at all ever since I was brought here.","TWN":"……還不是拜部長所賜，我來到這裡後眼睛完全沒閉過。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"물벼락을 맞으니 정신이 좀 드나?","JPN":"水を浴びて、少しは目が覚めたか？","ENG":"Recovering your senses after getting hit by water?","TWN":"潑完水有比較清醒一點吧？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그렇군. 나도 자네를 오랫동안 봐 오면서 이런 식으로 대하게 될 줄은 몰랐어.","JPN":"そうだな。君とは長い付き合いになるが、私もこんな風に対することになるとは思わなかった。","ENG":"I see. Knowing each other for so long, even I never thought things would come to this.","TWN":"我認識你這麼久，沒想到會有像這樣審問你的一天。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"다시 한 번 묻지.","JPN":"もう一度聞こう。","ENG":"I shall ask again.","TWN":"我再問你一次！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그날…… 파레마에서 자크를 사살한 이유가 뭔가?","JPN":"あの日……パレマでジャックを射殺した理由は何だ？","ENG":"That day... In Parema, why did you kill Jacques?","TWN":"那天……你在波雷馬射殺札克的理由是什麼？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……몇 번이나 말씀드렸을 텐데요. 저를 노린 저격에 대신 맞은 거라고.","JPN":"……何度も言ったはずです。私を狙った狙撃の代わりに撃たれたんだと。","ENG":"...How many times do I need to tell you. I was the actual target and he was hit instead of me.","TWN":"……到底要我說幾次，他是我的替死鬼，狙擊手原本的目標是我。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저격수를 찾아서 물어 보세요. 지금 수도에 와 있으니까요.","JPN":"スナイパーを探して聞いてみてください。今首都に来ていますから。","ENG":"Find the sniper and ask her. She’s in the capital right now.","TWN":"不信你自己去問找狙擊手問吧，反正你現在人就在首都。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"반군들을 이용하는 위험인물입니다. 내버려 두면 무슨 짓을 저지를지 몰라요.","JPN":"反乱軍を利用している危険人物です。放っておいたら何をしでかすかわかりません。","ENG":"She’s a dangerous figure. She is using the rebels for her own ends. If you leave her alone, there’s no telling what she could do.","TWN":"而且她可是會利用叛軍的危險人物，放著不管不知道會做出什麼事來。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그래? 처음부터 목격자들을 없애려고 자네가 끌어들인 강경파 인물이 아니라?","JPN":"本当か？　最初から目撃者を消すために、君が引き込んだ強硬派の人物ではなく？","ENG":"Is that so? Or is it someone from the hardliners you dragged into your plot in order to help eliminate witnesses?","TWN":"是嗎？她不是你用來將目擊者滅口的強硬派人士嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 애초에 절 죽이려고 수도까지 쫓아오지도 않았겠죠.","JPN":"だったら初めから私を殺すために首都まで追ってこなかったでしょう。","ENG":"If that were the case she wouldn’t have chased me all the way to the capital to kill me.","TWN":"如果是這樣，那她幹嘛還追到首都來要殺我？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"도심에서 벌어진 난전에 대해서는 보고 받았어.","JPN":"都心で起こった乱戦については報告を受けている。","ENG":"I’ve already been briefed about what occurred in the city.","TWN":"關於在市中心發生的混戰，我是有收到報告。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"하지만 지금은 그것도 자작극이 아닐지 의심스러운 판국이야.","JPN":"だが今はそれも自作自演ではないか疑わしい状況だ。","ENG":"But now I cannot help but wonder if this was also part of your plot.","TWN":"但我現在也很懷疑，那是不是你自導自演的。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……믿음을 가져 보시죠, 국장님.","JPN":"……信じてみてはどうですか、局長。","ENG":"... Trust me, Chief.","TWN":"……你相信我吧，部長！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};